import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Chip,
  Avatar,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  IconButton,
} from "@mui/material";
import DashboardIcon from "@mui/icons-material/Dashboard";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import PersonIcon from "@mui/icons-material/Person";
import CalendarMonthIcon from "@mui/icons-material/CalendarMonth";
import AddIcon from "@mui/icons-material/Add";
import EditIcon from "@mui/icons-material/Edit";
import DeleteIcon from "@mui/icons-material/Delete";

// Initial fake data (will be loaded/saved to localStorage)
const initialHospitals = [
  { id: 1, name: "City Care Hospital", location: "Kathmandu" },
  { id: 2, name: "Green Valley Medical Center", location: "Pokhara" },
  { id: 3, name: "Sunrise Hospital", location: "Lalitpur" },
];

const initialDoctors = [
  { id: 101, name: "Dr. Aashish Das", specialty: "Cardiology" },
  { id: 102, name: "Dr. Neha Sharma", specialty: "Neurology" },
  { id: 103, name: "Dr. Suman Thapa", specialty: "Orthopedics" },
];

const initialAppointments = [
  {
    patient: "Sita Shrestha",
    doctor: "Dr. Aashish Das",
    hospital: "City Care Hospital",
    date: "15 May 2024",
    status: "Scheduled",
  },
  {
    patient: "Ganesh Thapa",
    doctor: "Dr. Neha Sharma",
    hospital: "Green Valley Medical Center",
    date: "16 May 2024",
    status: "Scheduled",
  },
  {
    patient: "Mina Shali",
    doctor: "Dr. Suman Thapa",
    hospital: "Sunrise Hospital",
    date: "17 May 2024",
    status: "Completed",
  },
];

const getStatusChip = (status) => {
  const colors = {
    Scheduled: "warning",
    Completed: "success",
    Cancelled: "error",
  };
  return (
    <Chip
      label={status}
      color={colors[status] || "default"}
      size="small"
      sx={{ fontWeight: "medium" }}
    />
  );
};

const AdminDashboard = () => {
  const navigate = useNavigate();

  // Protect route - redirect if not logged in
  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isAdminLoggedIn");
    if (isLoggedIn !== "true") {
      navigate("/admin/login");
    }
  }, [navigate]);

  const [activeTab, setActiveTab] = useState("dashboard");

  // Data states (loaded from localStorage)
  const [hospitals, setHospitals] = useState(() => {
    const saved = localStorage.getItem("hospitals");
    return saved ? JSON.parse(saved) : initialHospitals;
  });

  const [doctors, setDoctors] = useState(() => {
    const saved = localStorage.getItem("doctors");
    return saved ? JSON.parse(saved) : initialDoctors;
  });

  const [appointments, setAppointments] = useState(() => {
    const saved = localStorage.getItem("appointments");
    return saved ? JSON.parse(saved) : initialAppointments;
  });

  // Modal state
  const [openModal, setOpenModal] = useState(false);
  const [modalType, setModalType] = useState(""); // "addHospital", "editHospital", "addDoctor", "editDoctor"
  const [currentItem, setCurrentItem] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    location: "",
    specialty: "",
  });

  // Save data to localStorage whenever it changes
  useEffect(() => {
    localStorage.setItem("hospitals", JSON.stringify(hospitals));
    localStorage.setItem("doctors", JSON.stringify(doctors));
    localStorage.setItem("appointments", JSON.stringify(appointments));
  }, [hospitals, doctors, appointments]);

  // Modal open handlers
  const openModalHandler = (type, item = null) => {
    setModalType(type);
    setCurrentItem(item);
    if (item) {
      setFormData({
        name: item.name || "",
        location: item.location || "",
        specialty: item.specialty || "",
      });
    } else {
      setFormData({ name: "", location: "", specialty: "" });
    }
    setOpenModal(true);
  };

  const handleSave = () => {
    if (!formData.name.trim()) return alert("Name is required");

    if (modalType === "addHospital") {
      setHospitals([...hospitals, { id: Date.now(), ...formData }]);
    } else if (modalType === "editHospital") {
      setHospitals(
        hospitals.map((h) =>
          h.id === currentItem.id ? { ...h, ...formData } : h,
        ),
      );
    } else if (modalType === "addDoctor") {
      setDoctors([...doctors, { id: Date.now(), ...formData }]);
    } else if (modalType === "editDoctor") {
      setDoctors(
        doctors.map((d) =>
          d.id === currentItem.id ? { ...d, ...formData } : d,
        ),
      );
    }

    setOpenModal(false);
  };

  const handleDelete = (type, id) => {
    if (window.confirm(`Are you sure you want to delete this ${type}?`)) {
      if (type === "hospital")
        setHospitals(hospitals.filter((h) => h.id !== id));
      if (type === "doctor") setDoctors(doctors.filter((d) => d.id !== id));
    }
  };

  return (
    <Box sx={{ display: "flex", minHeight: "100vh", bgcolor: "#f5f5f5" }}>
      {/* Sidebar */}
      <Box sx={{ width: 280, bgcolor: "#1a3c5e", color: "white", p: 3 }}>
        <Typography
          variant="h5"
          sx={{ mb: 4, fontWeight: "bold", textAlign: "center" }}
        >
          Admin Dashboard
        </Typography>

        <List>
          {[
            { label: "Dashboard", value: "dashboard", icon: <DashboardIcon /> },
            {
              label: "Hospitals",
              value: "hospitals",
              icon: <LocalHospitalIcon />,
            },
            { label: "Doctors", value: "doctors", icon: <PersonIcon /> },
            {
              label: "Appointments",
              value: "appointments",
              icon: <CalendarMonthIcon />,
            },
          ].map((item) => (
            <ListItem
              button
              key={item.value}
              sx={{
                bgcolor: activeTab === item.value ? "#2c5282" : "transparent",
                borderRadius: 1,
                mb: 1,
              }}
              onClick={() => setActiveTab(item.value)}
            >
              <ListItemIcon sx={{ color: "white" }}>{item.icon}</ListItemIcon>
              <ListItemText primary={item.label} />
            </ListItem>
          ))}
        </List>
      </Box>

      {/* Main Content */}
      <Box component="main" sx={{ flexGrow: 1, p: 4 }}>
        <Typography variant="h4" fontWeight="bold" gutterBottom>
          {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
        </Typography>

        {/* Dashboard */}
        {activeTab === "dashboard" && (
          <Grid container spacing={3}>
            <Grid item xs={12} sm={4}>
              <Card sx={{ bgcolor: "#e3f2fd" }}>
                <CardContent sx={{ textAlign: "center" }}>
                  <Typography variant="h3" color="primary">
                    {hospitals.length}
                  </Typography>
                  <Typography variant="h6">Total Hospitals</Typography>
                </CardContent>
              </Card>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Card sx={{ bgcolor: "#e8f5e9" }}>
                <CardContent sx={{ textAlign: "center" }}>
                  <Typography variant="h3" color="success.main">
                    {doctors.length}
                  </Typography>
                  <Typography variant="h6">Total Doctors</Typography>
                </CardContent>
              </Card>
            </Grid>
            <Grid item xs={12} sm={4}>
              <Card sx={{ bgcolor: "#fff3e0" }}>
                <CardContent sx={{ textAlign: "center" }}>
                  <Typography variant="h3" color="warning.main">
                    {appointments.length}
                  </Typography>
                  <Typography variant="h6">Total Appointments</Typography>
                </CardContent>
              </Card>
            </Grid>
          </Grid>
        )}

        {/* Hospitals */}
        {activeTab === "hospitals" && (
          <Paper sx={{ p: 3 }}>
            <Box
              sx={{ display: "flex", justifyContent: "space-between", mb: 3 }}
            >
              <Typography variant="h6" fontWeight="bold">
                Manage Hospitals
              </Typography>
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => openModalHandler("addHospital")}
              >
                Add Hospital
              </Button>
            </Box>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Name</TableCell>
                    <TableCell>Location</TableCell>
                    <TableCell align="right">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {hospitals.map((h) => (
                    <TableRow key={h.id}>
                      <TableCell>{h.name}</TableCell>
                      <TableCell>{h.location}</TableCell>
                      <TableCell align="right">
                        <IconButton
                          color="primary"
                          size="small"
                          onClick={() => openModalHandler("editHospital", h)}
                        >
                          <EditIcon />
                        </IconButton>
                        <IconButton
                          color="error"
                          size="small"
                          onClick={() => handleDelete("hospital", h.id)}
                        >
                          <DeleteIcon />
                        </IconButton>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}

        {/* Doctors */}
        {activeTab === "doctors" && (
          <Paper sx={{ p: 3 }}>
            <Box
              sx={{ display: "flex", justifyContent: "space-between", mb: 3 }}
            >
              <Typography variant="h6" fontWeight="bold">
                Manage Doctors
              </Typography>
              <Button
                variant="contained"
                startIcon={<AddIcon />}
                onClick={() => openModalHandler("addDoctor")}
              >
                Add Doctor
              </Button>
            </Box>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Name</TableCell>
                    <TableCell>Specialty</TableCell>
                    <TableCell align="right">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {doctors.map((d) => (
                    <TableRow key={d.id}>
                      <TableCell>{d.name}</TableCell>
                      <TableCell>{d.specialty}</TableCell>
                      <TableCell align="right">
                        <IconButton
                          color="primary"
                          size="small"
                          onClick={() => openModalHandler("editDoctor", d)}
                        >
                          <EditIcon />
                        </IconButton>
                        <IconButton
                          color="error"
                          size="small"
                          onClick={() => handleDelete("doctor", d.id)}
                        >
                          <DeleteIcon />
                        </IconButton>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}

        {/* Appointments */}
        {activeTab === "appointments" && (
          <Paper sx={{ p: 4 }}>
            <Typography variant="h6" fontWeight="bold" gutterBottom>
              Recent Appointments
            </Typography>
            <TableContainer sx={{ mt: 2 }}>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>Patient</TableCell>
                    <TableCell>Doctor</TableCell>
                    <TableCell>Hospital</TableCell>
                    <TableCell>Date</TableCell>
                    <TableCell>Status</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {appointments.map((a, i) => (
                    <TableRow key={i}>
                      <TableCell>{a.patient}</TableCell>
                      <TableCell>{a.doctor}</TableCell>
                      <TableCell>{a.hospital}</TableCell>
                      <TableCell>{a.date}</TableCell>
                      <TableCell>{getStatusChip(a.status)}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>
        )}
      </Box>

      {/* Add/Edit Modal */}
      <Dialog
        open={openModal}
        onClose={() => setOpenModal(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>
          {modalType.includes("add") ? "Add" : "Edit"}{" "}
          {modalType.includes("Hospital") ? "Hospital" : "Doctor"}
        </DialogTitle>
        <DialogContent>
          <TextField
            fullWidth
            label="Name"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
            sx={{ mt: 2 }}
          />
          {modalType.includes("Hospital") && (
            <TextField
              fullWidth
              label="Location"
              value={formData.location}
              onChange={(e) =>
                setFormData({ ...formData, location: e.target.value })
              }
              sx={{ mt: 2 }}
            />
          )}
          {modalType.includes("Doctor") && (
            <TextField
              fullWidth
              label="Specialty"
              value={formData.specialty}
              onChange={(e) =>
                setFormData({ ...formData, specialty: e.target.value })
              }
              sx={{ mt: 2 }}
            />
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenModal(false)}>Cancel</Button>
          <Button onClick={handleSave} variant="contained">
            Save
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default AdminDashboard;
